 43→function filterSections(sections: SectionData[], query: string): SectionData[] {
 44→  if (!query) return sections;
 45→  const lower = query.toLowerCase();
 46→  return sections
 47→    .map(section => ({
 48→      ...section,
 49→      items: section.items.filter(
 50→        item =>
 51→          item.title.toLowerCase().includes(lower) ||
 52→          item.subtitle?.toLowerCase().includes(lower),
 53→      ),
 54→    }))
 55→    .filter(section => section.items.length > 0);
 56→}
 57→
 58→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 59→  if (!query) return colors;
 60→  const lower = query.toLowerCase();
 61→  return colors.filter(
 62→    c =>
 63→      c.title.toLowerCase().includes(lower) ||
 64→      c.subtitle?.toLowerCase().includes(lower),
 65→  );
 66→}
 67→
 68→function flattenItems(sections: SectionData[]): ListItemData[] {
 69→  return sections.flatMap(s => s.items);
 70→}
