416→      },
417→      {
418→        title: 'Danger Zone',
419→        actions: [
420→          {
421→            label: 'Delete',
422→            shortcut: (
423→              <Kbd
424→                keys={[
425→                  '⌘',
426→                  '⌫',
427→                ]}
428→              />
429→            ),
430→            onClick: handleDelete,
431→          },
432→        ],
433→      },
434→    ],
435→    [
436→      selectedEntry?.pinned,
437→      handlePaste,
438→      handleCopy,
439→      handleTogglePin,
440→      handleDelete,
441→    ],
442→  );
443→
444→  const activeDescendantId =
445→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
446→
447→  return (
448→    <>
449→      <SearchBar
450→        value={query}
451→        onChange={handleQueryChange}
452→        placeholder="Search Clipboard History..."
